## TypeScript Cheat Sheet

### Basic Types
```typescript
let name: string = "Alice";
let age: number = 30;
let active: boolean = true;
let scores: number[] = [90, 85, 92];
let data: unknown;    // must type-check before use
let wild: any;        // disables type checking (avoid)
```

### Object Types (Interface vs Type)
```typescript
interface User {
  id: number;
  name: string;
  email: string;
  role?: string;      // optional field
  readonly createdAt: Date;  // immutable
}

type Product = {
  id: string;
  price: number;
  category: 'electronics' | 'clothing' | 'food'; // union
};
```

### Function Types
```typescript
function greet(name: string, greeting = 'Hello'): string {
  return `${greeting}, ${name}!`;
}

// Arrow function
const add = (a: number, b: number): number => a + b;

// Generic function
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}
```

### Utility Types
```typescript
Partial<User>        // all fields optional
Required<User>       // all fields required
Readonly<User>       // all fields readonly
Pick<User, 'name' | 'email'>  // subset of fields
Omit<User, 'password'>        // exclude fields
Record<string, number>        // dictionary type
```
